use std::collections::VecDeque;

struct StateMachineIterator {
    data: VecDeque<i32>,
    index: usize,
}

impl Iterator for StateMachineIterator {
    type Item = i32;

    fn next(&mut self) -> Option<Self::Item> {
        if self.index >= self.data.len() {
            return None;
        }
        let item = self.data[self.index];
        self.index += 1;
        Some(item)
    }
}

fn main() {
    let raw_data = vec![10, 20, 30, 40, 50];
    let initial_queue: VecDeque<i32> = raw_data.into_iter().collect();

    let mut iterator = StateMachineIterator {
        data: initial_queue,
        index: 0,
    };

    let processed_items: Vec<i32> = iterator.by_ref().collect();

    println!("Processed items: {:?}", processed_items);
}
